+// Package skiplist implements a concurrent skip list with lazy synchronization
+// and atomics, as required by the OwlDB project specification.
+//
+// The skip list uses:
+//   - Lazy synchronization: nodes are logically deleted (marked) before
+//     being physically removed from the list.
+//   - Per-node mutexes for insertion/deletion.
+//   - Atomic flags for 'marked' (logically deleted) and 'fullyLinked' states.
+//   - Go generics with cmp.Ordered keys and any values.
+package skiplist
+
+import (
+	"cmp"
+	"context"
+	"math"
+	"math/rand"
+	"sync"
+	"sync/atomic"
+)
+
+const maxLevel = 16
+
+// UpdateCheck is a function called by Upsert while holding the target node's
+// lock. It receives the key, the current value (or zero value if not exists),
+// and whether a value already exists. It returns the new value or an error.
+type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)
+
+// Pair is a key-value pair returned by Query.
+type Pair[K cmp.Ordered, V any] struct {
+	Key   K
+	Value V
+}
+
+// DBIndex is the interface for the skip list.
+type DBIndex[K cmp.Ordered, V any] interface {
+	Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error)
+	Remove(key K) (removedValue V, removed bool)
+	Find(key K) (foundValue V, found bool)
+	Query(ctx context.Context, start K, end K) (results []Pair[K, V], err error)
+}
+
+// node is a single node in the skip list.
+type node[K cmp.Ordered, V any] struct {
+	key        K
+	value      V
+	topLevel   int
+	nexts      [maxLevel]*node[K, V]
+	marked     atomic.Bool // logically deleted
+	fullyLinked atomic.Bool // physically linked at all levels
+	mu         sync.Mutex
+}
+
+// SkipList is a concurrent skip list with lazy synchronization.
+type SkipList[K cmp.Ordered, V any] struct {
+	head *node[K, V]
+	tail *node[K, V]
+}
+
+// New creates a new SkipList.
+func New[K cmp.Ordered, V any]() *SkipList[K, V] {
+	head := &node[K, V]{topLevel: maxLevel - 1}
+	tail := &node[K, V]{topLevel: maxLevel - 1}
+	for i := 0; i < maxLevel; i++ {
+		head.nexts[i] = tail
+	}
+	head.fullyLinked.Store(true)
+	tail.fullyLinked.Store(true)
+	return &SkipList[K, V]{head: head, tail: tail}
+}
+
+// randomLevel returns a random level for a new node.
+func randomLevel() int {
+	level := 0
+	for level < maxLevel-1 && rand.Float64() < 0.5 {
+		level++
+	}
+	return level
+}
+
+// find locates preds and succs for the given key at all levels.
+// Returns the level at which the key was found, or -1.
+func (s *SkipList[K, V]) find(key K, preds, succs []*node[K, V]) int {
+	foundLevel := -1
+	pred := s.head
+	for level := maxLevel - 1; level >= 0; level-- {
+		curr := pred.nexts[level]
+		for curr != s.tail && cmp.Compare(curr.key, key) < 0 {
+			pred = curr
+			curr = pred.nexts[level]
+		}
+		if foundLevel == -1 && curr != s.tail && cmp.Compare(curr.key, key) == 0 {
+			foundLevel = level
+		}
+		preds[level] = pred
+		succs[level] = curr
+	}
+	return foundLevel
+}
+
+// Upsert inserts or updates the value for the given key.
+// The check function is called with the node's lock held (if node exists).
+func (s *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error) {
+	var preds [maxLevel]*node[K, V]
+	var succs [maxLevel]*node[K, V]
+
+	for {
+		foundLevel := s.find(key, preds[:], succs[:])
+
+		if foundLevel != -1 {
+			// Key already exists
+			nodeFound := succs[foundLevel]
+			if nodeFound.marked.Load() {
+				// Node is being deleted, retry
+				continue
+			}
+			// Wait until fully linked
+			for !nodeFound.fullyLinked.Load() {
+			}
+			// Lock the node and call check function
+			nodeFound.mu.Lock()
+			if nodeFound.marked.Load() {
+				nodeFound.mu.Unlock()
+				continue
+			}
+			newVal, checkErr := check(key, nodeFound.value, true)
+			if checkErr != nil {
+				nodeFound.mu.Unlock()
+				return false, checkErr
+			}
+			nodeFound.value = newVal
+			nodeFound.mu.Unlock()
+			return true, nil
+		}
+
+		// Key not found - insert new node
+		topLevel := randomLevel()
+
+		// Lock all necessary predecessors (each unique predecessor only once)
+		valid := true
+		var lockedPreds []*node[K, V]
+		lockedSet := make(map[*node[K, V]]bool)
+
+		for level := 0; level <= topLevel; level++ {
+			pred := preds[level]
+			succ := succs[level]
+
+			if !lockedSet[pred] {
+				pred.mu.Lock()
+				lockedPreds = append(lockedPreds, pred)
+				lockedSet[pred] = true
+			}
+
+			if pred.marked.Load() || succ.marked.Load() || pred.nexts[level] != succ {
+				valid = false
+				break
+			}
+		}
+
+		if !valid {
+			for _, p := range lockedPreds {
+				p.mu.Unlock()
+			}
+			continue
+		}
+
+		// Call check to get initial value
+		var zero V
+		newVal, checkErr := check(key, zero, false)
+		if checkErr != nil {
+			for _, p := range lockedPreds {
+				p.mu.Unlock()
+			}
+			return false, checkErr
+		}
+
+		// Create new node
+		newNode := &node[K, V]{
+			key:      key,
+			value:    newVal,
+			topLevel: topLevel,
+		}
+
+		// Link new node at all levels
+		for level := 0; level <= topLevel; level++ {
+			newNode.nexts[level] = succs[level]
+			preds[level].nexts[level] = newNode
+		}
+		newNode.fullyLinked.Store(true)
+
+		for _, p := range lockedPreds {
+			p.mu.Unlock()
+		}
+		return false, nil
+	}
+}
+
+// Remove removes the node with the given key.
+// Returns the removed value and true if found, or zero value and false.
+func (s *SkipList[K, V]) Remove(key K) (removedValue V, removed bool) {
+	var preds [maxLevel]*node[K, V]
+	var succs [maxLevel]*node[K, V]
+	var victim *node[K, V]
+	isMarked := false
+
+	for {
+		foundLevel := s.find(key, preds[:], succs[:])
+
+		if isMarked || (foundLevel != -1 && canDelete(succs[foundLevel], foundLevel)) {
+			if !isMarked {
+				victim = succs[foundLevel]
+				victim.mu.Lock()
+				if victim.marked.Load() {
+					victim.mu.Unlock()
+					var zero V
+					return zero, false
+				}
+				victim.marked.Store(true)
+				isMarked = true
+			}
+
+			// Lock predecessors and physically remove
+			var lockedPreds []*node[K, V]
+			valid := true
+			highestLocked := -1
+
+			for level := 0; level <= victim.topLevel; level++ {
+				pred := preds[level]
+				if level == 0 || preds[level] != preds[level-1] {
+					pred.mu.Lock()
+					lockedPreds = append(lockedPreds, pred)
+					highestLocked = level
+				}
+				if pred.marked.Load() || pred.nexts[level] != victim {
+					valid = false
+					break
+				}
+			}
+			_ = highestLocked
+
+			if !valid {
+				for _, p := range lockedPreds {
+					p.mu.Unlock()
+				}
+				continue
+			}
+
+			// Physically remove
+			for level := victim.topLevel; level >= 0; level-- {
+				preds[level].nexts[level] = victim.nexts[level]
+			}
+			victim.mu.Unlock()
+			for _, p := range lockedPreds {
+				p.mu.Unlock()
+			}
+			return victim.value, true
+		}
+		var zero V
+		return zero, false
+	}
+}
+
+func canDelete[K cmp.Ordered, V any](n *node[K, V], foundLevel int) bool {
+	return n.fullyLinked.Load() && n.topLevel == foundLevel && !n.marked.Load()
+}
+
+// Find returns the value for the given key, or false if not found.
+func (s *SkipList[K, V]) Find(key K) (foundValue V, found bool) {
+	var preds [maxLevel]*node[K, V]
+	var succs [maxLevel]*node[K, V]
+	foundLevel := s.find(key, preds[:], succs[:])
+	if foundLevel != -1 {
+		n := succs[foundLevel]
+		if n.fullyLinked.Load() && !n.marked.Load() {
+			return n.value, true
+		}
+	}
+	var zero V
+	return zero, false
+}
+
+// Query returns all key-value pairs with keys in [start, end] in sorted order.
+// Uses math.IsInf trick: if start is "" and end is "" (empty strings), treat as unbounded.
+// For generic K: we accept the sentinel values (a key less than all others for start
+// and greater than all for end).
+//
+// The start and end bounds are inclusive. Empty string "" means no bound.
+func (s *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
+	var results []Pair[K, V]
+
+	curr := s.head.nexts[0]
+	for curr != s.tail {
+		select {
+		case <-ctx.Done():
+			return results, ctx.Err()
+		default:
+		}
+
+		if !curr.marked.Load() && curr.fullyLinked.Load() {
+			key := curr.key
+			inRange := true
+
+			// Check if we have a real start bound (use sentinel detection via maxKey/minKey)
+			if !isMinSentinel(start) && cmp.Compare(key, start) < 0 {
+				inRange = false
+			}
+			if !isMaxSentinel(end) && cmp.Compare(key, end) > 0 {
+				inRange = false
+			}
+
+			if inRange {
+				results = append(results, Pair[K, V]{Key: key, Value: curr.value})
+			}
+
+			// If past end, we can stop (skip list is sorted)
+			if !isMaxSentinel(end) && cmp.Compare(key, end) > 0 {
+				break
+			}
+		}
+		curr = curr.nexts[0]
+	}
+	return results, nil
+}
+
+// isMinSentinel checks if a key is the minimum sentinel value.
+func isMinSentinel[K cmp.Ordered](k K) bool {
+	// For strings: empty string "" is treated as "no lower bound"
+	// For other types we rely on math.IsInf-style detection
+	switch v := any(k).(type) {
+	case string:
+		return v == ""
+	case float64:
+		return math.IsInf(v, -1)
+	case int:
+		return v == math.MinInt
+	case int64:
+		return v == math.MinInt64
+	}
+	return false
+}
+
+// isMaxSentinel checks if a key is the maximum sentinel value.
+func isMaxSentinel[K cmp.Ordered](k K) bool {
+	switch v := any(k).(type) {
+	case string:
+		return v == ""
+	case float64:
+		return math.IsInf(v, 1)
+	case int:
+		return v == math.MaxInt
+	case int64:
+		return v == math.MaxInt64
+	}
+	return false
+}
